import { Component, Input, OnInit } from '@angular/core';
import { AuthService } from '../../../core/services/auth.service';

@Component({
  selector: 'app-header',
  templateUrl: './header.component.html',
  styleUrls: ['./header.component.scss'],
})
export class HeaderComponent implements OnInit {
  @Input() showHistory = true;
  @Input() showDashboard = false;

  userLabel = '';
  userAvatar = '';
  isGoogle = false;

  constructor(public auth: AuthService) {}

  ngOnInit(): void {
    try {
      const mode = localStorage.getItem('mode');
      if (mode === 'guest') {
        this.userLabel = '👤 Guest';
        return;
      }
      const u = JSON.parse(localStorage.getItem('user') || 'null');
      if (u) {
        this.userLabel = `${u.firstName || ''} ${u.lastName || ''}`.trim();
        this.userAvatar = u.profilePictureUrl || '';
        this.isGoogle = !!u.googleId;
      }
    } catch { /* noop */ }
  }

  logout(): void { this.auth.logout(); }
}
<header class="header">
  <div class="header-brand">
    <span class="header-icon">📐</span>
    <span class="header-title">Quantity Measurement</span>
  </div>
  <div class="header-right">
    <a *ngIf="showHistory" routerLink="/history" class="btn btn-ghost btn-sm">📋 History</a>
    <a *ngIf="showDashboard" routerLink="/dashboard" class="btn btn-ghost btn-sm">⬅ Dashboard</a>
    <span class="user-badge" *ngIf="userLabel">
      <ng-container *ngIf="userAvatar">
        <img [src]="userAvatar" alt="Profile" class="user-avatar" />
      </ng-container>
      <span class="user-name">{{ userLabel }}</span>
      <span class="auth-badge" *ngIf="isGoogle">G</span>
    </span>
    <button class="btn btn-ghost btn-sm" (click)="logout()">Logout</button>
  </div>
</header>
